css:
* { margin: 0; padding: 0; box-sizing: border-box; font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif; }
body { background: #0a0a0a; color: white; }
.navbar { display: flex; align-items: center; justify-content: space-between; padding: 22px 60px; }
.brand { font-size: 19px; font-weight: 900; letter-spacing: 0.05em; }
.nav-links { display: flex; gap: 28px; }
.nav-links a { color: rgba(255,255,255,0.5); text-decoration: none; font-size: 14px; font-weight: 700; text-transform: uppercase; letter-spacing: 0.03em; }
.nav-links a.active { color: #facc15; }
.cart-icon { font-size: 15px; font-weight: 700; cursor: pointer; }
.hero { padding: 70px 60px; background: linear-gradient(135deg, #1a1a1a, #0a0a0a); }
.hero-text { max-width: 560px; }
.badge { display: inline-block; color: #facc15; font-size: 12px; font-weight: 800; letter-spacing: 0.18em; margin-bottom: 22px; }
.hero h1 { font-size: 56px; font-weight: 900; line-height: 1.1; margin-bottom: 20px; text-transform: uppercase; }
.hero h1 span { color: #facc15; }
.hero p { color: rgba(255,255,255,0.5); font-size: 15px; line-height: 1.8; margin-bottom: 28px; }
.btn-primary { background: #facc15; color: #0a0a0a; border: none; padding: 16px 32px; font-size: 13px; font-weight: 800; text-transform: uppercase; letter-spacing: 0.08em; cursor: pointer; }
.products { padding: 50px 60px; }
.filter-row { display: flex; gap: 10px; margin-bottom: 30px; flex-wrap: wrap; }
.filter { background: rgba(255,255,255,0.05); border: 1px solid rgba(255,255,255,0.1); color: rgba(255,255,255,0.5); padding: 9px 18px; border-radius: 999px; font-size: 13px; font-weight: 700; cursor: pointer; }
.filter.active { background: rgba(250,204,21,0.15); color: #facc15; border-color: rgba(250,204,21,0.3); }
.product-grid { display: grid; grid-template-columns: repeat(auto-fill, minmax(200px, 1fr)); gap: 20px; }
.product-card { cursor: pointer; }
.product-img { aspect-ratio: 1; background: rgba(255,255,255,0.04); border-radius: 14px; display: flex; align-items: center; justify-content: center; font-size: 48px; margin-bottom: 12px; transition: 0.2s; border: 1px solid rgba(255,255,255,0.06); }
.product-card:hover .product-img { background: rgba(250,204,21,0.08); border-color: rgba(250,204,21,0.2); }
.product-card h3 { font-size: 14.5px; font-weight: 700; margin-bottom: 4px; }
.cat-label { display: block; font-size: 11.5px; color: rgba(255,255,255,0.4); text-transform: uppercase; letter-spacing: 0.05em; margin-bottom: 6px; }
.price { color: #facc15; font-weight: 800; font-size: 14px; }
.cart-drawer { position: fixed; top: 0; right: -380px; width: 360px; height: 100%; background: #141414; box-shadow: -10px 0 40px rgba(0,0,0,0.4); z-index: 20; transition: right 0.3s; display: flex; flex-direction: column; }
.cart-drawer.open { right: 0; }
.cart-header { display: flex; justify-content: space-between; align-items: center; padding: 24px; border-bottom: 1px solid rgba(255,255,255,0.06); }
.cart-header h2 { font-size: 18px; font-weight: 800; }
.cart-header button { background: none; border: none; color: white; font-size: 18px; cursor: pointer; }
.cart-items { flex: 1; overflow-y: auto; padding: 16px 24px; display: flex; flex-direction: column; gap: 14px; }
.cart-item { display: flex; gap: 14px; align-items: center; }
.cart-item-img { width: 56px; height: 56px; background: rgba(255,255,255,0.05); border-radius: 12px; display: flex; align-items: center; justify-content: center; font-size: 22px; flex-shrink: 0; }
.cart-item-info { flex: 1; }
.cart-item-info h4 { font-size: 13.5px; font-weight: 700; }
.cart-item-info span { font-size: 12.5px; color: rgba(255,255,255,0.4); }
.remove-btn { background: none; border: none; color: rgba(255,255,255,0.3); font-size: 14px; cursor: pointer; }
.cart-footer { padding: 24px; border-top: 1px solid rgba(255,255,255,0.06); }
.cart-total { display: flex; justify-content: space-between; font-size: 16px; font-weight: 800; margin-bottom: 16px; }
.btn-primary.full { width: 100%; padding: 15px; border-radius: 10px; }
.overlay { position: fixed; inset: 0; background: rgba(0,0,0,0.5); display: none; z-index: 19; }
.overlay.show { display: block; }
@media (max-width: 900px) { .navbar, .hero, .products { padding-left: 24px; padding-right: 24px; } .nav-links { display: none; } .hero h1 { font-size: 38px; } .cart-drawer { width: 100%; right: -100%; } }

